function About() {
  return (
    <section className="about-section" id="about">
      <h2>Our Story</h2>
      <p>
        Where every cup comes with a purr!
        At Meow Café, you can sip your 
        favorite coffee, enjoy sweet treats,
        and spend time with our adorable furry
         friends. Every visit is filled with cozy
          vibes, tiny paws, and happy hearts.
      </p>
    </section>
  );
}

export default About;
